import Component from 'flarum/common/Component';
import app from 'flarum/forum/app';
import icon from 'flarum/common/helpers/icon';

/**
 * MarketplacePromoCard â€” purple-gradient CTA in the IndexPage sidebar
 * pointing visitors at the marketplace storefront.
 *
 * Auto-hides if the marketplace extension isn't installed (detected via
 * `app.forum.attribute('marketplaceUrl')` â€” set by ramon/marketplace).
 */
export default class MarketplacePromoCard extends Component {
  view() {
    const url = app.forum.attribute('marketplaceUrl') || '/marketplace';

    /* If the operator opts out, hide. */
    if (app.forum.attribute('edonlineHideMarketplacePromo')) return null;
    return m("a", {
      className: "EdonlineSideCard EdonlineMarketplacePromo",
      href: url
    }, m("div", {
      className: "EdonlineMarketplacePromo-bg"
    }, icon('fas fa-store')), m("div", {
      className: "EdonlineMarketplacePromo-inner"
    }, m("div", {
      className: "EdonlineMarketplacePromo-kicker"
    }, "NEW \xB7 Marketplace"), m("div", {
      className: "EdonlineMarketplacePromo-title"
    }, "Premium themes & extensions"), m("div", {
      className: "EdonlineMarketplacePromo-desc"
    }, "Digital products, services, subscriptions, and private extensions from trusted sellers."), m("div", {
      className: "EdonlineMarketplacePromo-cta"
    }, "Browse the store ", icon('fas fa-arrow-right', {
      style: {
        fontSize: '11px'
      }
    }))));
  }
}
flarum.reg.add('ernestdefoe-edonline', 'forum/components/MarketplacePromoCard', MarketplacePromoCard);